<template><el-card v-if="data"><template #header><div class="head"><b>居住证详情</b><div><el-button v-if="data.status==='ACTIVE'&&user.hasPermission('residence-permit:apply')" @click="$router.push(`/residence-permits/${data.permitId}/endorsement`)">申请签注</el-button><el-button v-if="data.status==='ACTIVE'&&user.hasPermission('residence-permit:apply')" type="danger" @click="$router.push(`/residence-permits/${data.permitId}/cancellation`)">申请注销</el-button></div></div></template><el-descriptions border :column="2"><el-descriptions-item v-for="(v,k) in data" :key="k" :label="k">{{v}}</el-descriptions-item></el-descriptions><el-divider>生命周期时间线</el-divider><el-timeline><el-timeline-item v-for="x in logs" :key="x.permitLogId" :timestamp="x.operationTime">{{x.action}}：{{x.fromStatus||'-'}} → {{x.toStatus}}</el-timeline-item></el-timeline><el-alert title="课程模拟系统生成，不作为真实政务证件" type="warning"/></el-card></template>
<script setup>import{ref,onMounted}from'vue';import{useRoute}from'vue-router';import{useUserStore}from'../../stores/user';import{getPermit,getPermitLogs}from'../../api/floatingResidence';const route=useRoute(),user=useUserStore(),data=ref(),logs=ref([]);onMounted(async()=>{data.value=await getPermit(route.params.id);logs.value=await getPermitLogs(route.params.id)})</script><style scoped>.head{display:flex;justify-content:space-between}</style>
